import{c as t,Q as s,j as a,m as n}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Claude Code Harness: The Runtime Architecture That Turns an LLM into an Autonomous Agent (2026 Guide)","description":"","frontmatter":{"title":"Claude Code Harness: The Runtime Architecture That Turns an LLM into an Autonomous Agent (2026 Guide)","date":"2026-03-01T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-03-01-claude-code-harness-runtime-architecture-pasqualepillitteri.md","filePath":"research/ai-articles/scored/2026-03-01-claude-code-harness-runtime-architecture-pasqualepillitteri.md","lastUpdated":1779796674000}'),o={name:"research/ai-articles/scored/2026-03-01-claude-code-harness-runtime-architecture-pasqualepillitteri.md"};function i(r,e,l,d,h,c){return s(),a("div",null,[...e[0]||(e[0]=[n(`<blockquote><p>Source: <a href="https://pasqualepillitteri.it/en/news/1892/claude-code-harness-runtime-architecture-2026-guide" target="_blank" rel="noreferrer">https://pasqualepillitteri.it/en/news/1892/claude-code-harness-runtime-architecture-2026-guide</a> Fetched: 2026-05-08</p></blockquote><h1 id="claude-code-harness-the-runtime-architecture-that-turns-an-llm-into-an-autonomous-agent-2026-guide" tabindex="-1">Claude Code Harness: The Runtime Architecture That Turns an LLM into an Autonomous Agent (2026 Guide) <a class="header-anchor" href="#claude-code-harness-the-runtime-architecture-that-turns-an-llm-into-an-autonomous-agent-2026-guide" aria-label="Permalink to &quot;Claude Code Harness: The Runtime Architecture That Turns an LLM into an Autonomous Agent (2026 Guide)&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>The claude-opus-4-7 model functions as a token generator in isolation. Everything enabling Claude Code to read files, execute shell commands, open pull requests, and maintain session preferences exists in a software layer surrounding the model called the <strong>harness</strong>. This runtime architecture transforms a language model into an autonomous coding agent capable of real-world actions.</p><h2 id="what-an-agent-harness-is-and-why-the-model-alone-is-not-enough" tabindex="-1">What an Agent Harness Is and Why the Model Alone Is Not Enough <a class="header-anchor" href="#what-an-agent-harness-is-and-why-the-model-alone-is-not-enough" aria-label="Permalink to &quot;What an Agent Harness Is and Why the Model Alone Is Not Enough&quot;">​</a></h2><p>According to Anthropic&#39;s official documentation, &quot;Claude Code serves as the agentic harness around Claude: it provides the tools, context management, and execution environment that turn a language model into a capable coding agent.&quot;</p><p>The same model limited to text responses in claude.ai can modify source code, run tests, and commit changes when operating within Claude Code&#39;s harness. The distinction lies entirely in this surrounding framework rather than the model itself.</p><p>The typical Claude Code workflow follows three phases: gathering context, taking action, and verifying results. None of these phases executes within the model strictly speaking. The model determines what actions to take, while the harness handles file reading, command execution, permission checking, conversation storage, and networking.</p><h2 id="the-agent-loop-a-surprisingly-simple-core" tabindex="-1">The Agent Loop: A Surprisingly Simple Core <a class="header-anchor" href="#the-agent-loop-a-surprisingly-simple-core" aria-label="Permalink to &quot;The Agent Loop: A Surprisingly Simple Core&quot;">​</a></h2><p>The harness core consists of a straightforward iterative loop:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Main harness loop (simplified)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">while</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> needs_follow_up:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    history </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> gather_conversation_history()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    response </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> call_model(history, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">tools</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">available_tools)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tool_call </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> response.tool_calls:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        result </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> execute_tool(tool_call)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        history.append(result)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    needs_follow_up </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> response.stop_reason </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;end_turn&quot;</span></span></code></pre></div><p>Claude Code&#39;s apparent intelligence derives from this tight iterative cycle around the model. The model cannot perceive the loop itself; it only sees accumulated conversation history, decides whether to invoke tools or return final text, and the harness manages everything else. Anthropic deliberately avoided complex planning systems, instead relying on simple tool-calling loops that terminate when the model declares completion.</p><h2 id="the-real-components-of-the-claude-code-runtime" tabindex="-1">The Real Components of the Claude Code Runtime <a class="header-anchor" href="#the-real-components-of-the-claude-code-runtime" aria-label="Permalink to &quot;The Real Components of the Claude Code Runtime&quot;">​</a></h2><p>Eight independent components comprise the Claude Code harness:</p><h3 id="_1-tool-executor" tabindex="-1">1. Tool Executor <a class="header-anchor" href="#_1-tool-executor" aria-label="Permalink to &quot;1. Tool Executor&quot;">​</a></h3><p>This module transforms structured tool-use requests from the model into real actions. Native tools fall into five categories: file operations (Read, Write, Edit), search (Glob, Grep), execution (Bash with sandboxing), web (WebFetch, WebSearch), and code intelligence (definitions, references, compiler errors). Each execution ties to the original request through a call identifier, enabling the model to establish cause and effect.</p><h3 id="_2-permission-manager" tabindex="-1">2. Permission Manager <a class="header-anchor" href="#_2-permission-manager" aria-label="Permalink to &quot;2. Permission Manager&quot;">​</a></h3><p>Before tool execution, the harness validates permissions through four modes: default (confirmation required for edits and commands), auto-accept edits (auto-approves file modifications), plan mode (read-only operations only), and auto mode (uses a background safety classifier on Sonnet 4.6 evaluating only user requests and tool calls, not model prose).</p><h3 id="_3-hook-system" tabindex="-1">3. Hook System <a class="header-anchor" href="#_3-hook-system" aria-label="Permalink to &quot;3. Hook System&quot;">​</a></h3><p>Hooks are shell commands executed in response to lifecycle events. Documentation lists twelve hooks including SessionStart, UserPromptSubmit, PreToolUse, PostToolUse, and Stop. Configuration through settings.json enables context injection, dangerous command blocking, audit trail logging, and external system integration.</p><h3 id="_4-context-manager" tabindex="-1">4. Context Manager <a class="header-anchor" href="#_4-context-manager" aria-label="Permalink to &quot;4. Context Manager&quot;">​</a></h3><p>The context window (tokens the model sees per call) has hardware limits: 200K in standard versions, 1M in some enterprise configurations. Management techniques include older tool output cleanup, automatic conversation compaction, prompt caching with five-minute TTL, lazy MCP schema loading, and skill snapshots. Anthropic recommends placing persistent rules in CLAUDE.md files when context fills.</p><h3 id="_5-mcp-layer" tabindex="-1">5. MCP Layer <a class="header-anchor" href="#_5-mcp-layer" aria-label="Permalink to &quot;5. MCP Layer&quot;">​</a></h3><p>The Model Context Protocol enables adding third-party tools without recompilation. MCP servers define tools in JSON with descriptions and schemas. The harness acts as client, presenting tools as native ones to the model. To minimize token consumption, MCP schemas defer: the model sees only tool names until invoking specific tools, triggering full schema loading.</p><h3 id="_6-skill-system" tabindex="-1">6. Skill System <a class="header-anchor" href="#_6-skill-system" aria-label="Permalink to &quot;6. Skill System&quot;">​</a></h3><p>Skills bundle markdown and scripts encapsulating domain knowledge. Each skill directory contains a SKILL.md file with YAML frontmatter and descriptions the model reads at session start. Full skill content loads only upon model invocation through dedicated tools, maintaining low token costs. Anthropic maintains an official skill repository with growing community contributions.</p><h3 id="_7-subagent-framework" tabindex="-1">7. Subagent Framework <a class="header-anchor" href="#_7-subagent-framework" aria-label="Permalink to &quot;7. Subagent Framework&quot;">​</a></h3><p>Subagents are model instances with separate context windows and configurable tool subsets, spawnable from the main model through the Agent tool. They parallelize independent work, isolate research-heavy tasks preventing main conversation saturation, and specialize on domains (frontend, security, debugging). Subagents receive initial prompts, run private loops, and return summary messages. Configuration uses Markdown files with frontmatter under <code>.claude/agents/</code> (project level) or <code>~/.claude/agents/</code> (user level).</p><h3 id="_8-session-storage" tabindex="-1">8. Session Storage <a class="header-anchor" href="#_8-session-storage" aria-label="Permalink to &quot;8. Session Storage&quot;">​</a></h3><p>Conversations save in JSONL format (one JSON object per line) under <code>~/.claude/projects/</code>. This design enables: resuming interrupted sessions with <code>claude --continue</code>, forking with <code>--fork-session</code> or <code>/branch</code> exploring alternatives, and rewinding individual edits through checkpoint snapshots taken before modifications. Pressing Escape twice triggers rewinding—a local mechanism separate from git covering only file edits, not remote system side effects.</p><h2 id="the-three-execution-environments" tabindex="-1">The Three Execution Environments <a class="header-anchor" href="#the-three-execution-environments" aria-label="Permalink to &quot;The Three Execution Environments&quot;">​</a></h2><p>The Claude Code harness operates in three environments:</p><p><strong>Local:</strong> Default mode. Code runs on your machine with full filesystem, terminal, and git access. Maximum freedom with maximum responsibility.</p><p><strong>Cloud:</strong> Code executes on Anthropic-managed VMs. Useful for offloading lengthy tasks and working on non-local repositories. The harness remains identical; only the underlying filesystem changes.</p><p><strong>Remote Control:</strong> Code runs locally, but browser-based harness control bridges web UI with local power.</p><h2 id="settings-json-the-hierarchy-that-rules-everything" tabindex="-1">Settings.json: The Hierarchy That Rules Everything <a class="header-anchor" href="#settings-json-the-hierarchy-that-rules-everything" aria-label="Permalink to &quot;Settings.json: The Hierarchy That Rules Everything&quot;">​</a></h2><p>Configuration follows a three-tier hierarchy that cascades: <code>~/.claude/settings.json</code> (global preferences), <code>&lt;repo&gt;/.claude/settings.json</code> (project level, committable), and <code>&lt;repo&gt;/.claude/settings.local.json</code> (private overrides, non-committable). More local settings override global ones. Main fields include: permissions (tool pattern allowlists/denylists), hooks (event-to-command mapping), env (environment variables), model (default override), and statusLine (custom CLI badge).</p><p>The CLAUDE.md file at project level receives special attention: the harness reads it at every startup and injects it into system prompts as stable instructions. Similarly, the auto-memory system preserves learnings between sessions within <code>~/.claude/projects/&lt;repo&gt;/memory/</code>.</p><h2 id="comparison-with-codex-and-cursor" tabindex="-1">Comparison with Codex and Cursor <a class="header-anchor" href="#comparison-with-codex-and-cursor" aria-label="Permalink to &quot;Comparison with Codex and Cursor&quot;">​</a></h2><p><strong>OpenAI Codex</strong> integrates harness components more tightly with model APIs; tool calling is native to model specifications rather than a separate layer. <strong>Cursor</strong> prioritizes IDE integration and maintains code indices for context retrieval instead of loading entire files. Claude Code emphasizes transparency with explicit approval gates for destructive operations. Codex reduces latency through harness-model coupling, while Cursor minimizes context bloat through retrieval-based approaches.</p><h2 id="harness-security-the-real-differentiator" tabindex="-1">Harness Security: The Real Differentiator <a class="header-anchor" href="#harness-security-the-real-differentiator" aria-label="Permalink to &quot;Harness Security: The Real Differentiator&quot;">​</a></h2><p>The primary harness risk involves the model executing injected instructions from external content—a threat called prompt injection. The harness implements immutable system prompt rules preventing destructive actions without user confirmation, isolating untrusted content, and filtering output for copyright and privacy concerns.</p><p>Anthropic invested significantly in this layer because code-executing agents on personal filesystems represent attractive attack vectors. The Apple case involving CLAUDE.md files in the Support app demonstrated how sensitive harness metadata can be. Enterprise direction emphasizes code scanning and patch suggestions through Claude Security.</p><h2 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently Asked Questions&quot;">​</a></h2><h3 id="can-i-use-the-claude-code-harness-with-another-llm" tabindex="-1">Can I use the Claude Code harness with another LLM? <a class="header-anchor" href="#can-i-use-the-claude-code-harness-with-another-llm" aria-label="Permalink to &quot;Can I use the Claude Code harness with another LLM?&quot;">​</a></h3><p>No, not officially. The harness is designed for Anthropic&#39;s Claude API. Open source projects attempt model-agnostic abstractions but lack feature parity and Claude-specific optimizations like native prompt caching and deferred tools.</p><h3 id="what-distinguishes-claude-code-cli-from-the-claude-agent-sdk" tabindex="-1">What distinguishes Claude Code (CLI) from the Claude Agent SDK? <a class="header-anchor" href="#what-distinguishes-claude-code-cli-from-the-claude-agent-sdk" aria-label="Permalink to &quot;What distinguishes Claude Code (CLI) from the Claude Agent SDK?&quot;">​</a></h3><p>The SDK exposes the harness without the CLI. Both use identical primitives: agent loops, tool definitions, MCP clients, context management. The SDK enables custom agents within applications rather than terminal assistants, sharing the same underlying runtime.</p><h3 id="how-many-tokens-does-the-harness-consume-beyond-user-prompts" tabindex="-1">How many tokens does the harness consume beyond user prompts? <a class="header-anchor" href="#how-many-tokens-does-the-harness-consume-beyond-user-prompts" aria-label="Permalink to &quot;How many tokens does the harness consume beyond user prompts?&quot;">​</a></h3><p>Between 10K and 50K tokens of system overhead. The system prompt uses several thousand tokens for safety rules, tool definitions, and base instructions. Additional consumption includes variable CLAUDE.md content, capped auto-memory (25KB), unexecuted skill descriptions, and initial git state dumps. The <code>/context</code> command shows real-time breakdowns.</p><h3 id="does-the-harness-work-offline" tabindex="-1">Does the harness work offline? <a class="header-anchor" href="#does-the-harness-work-offline" aria-label="Permalink to &quot;Does the harness work offline?&quot;">​</a></h3><p>Only for local tools. Filesystem, Bash, Glob, and Grep operations run locally without network access. However, every loop iteration requires API calls for model decisions, preventing agent progression without connectivity. Experimental workarounds exist using local models through Ollama or vLLM with third-party harnesses, but official setups require connectivity.</p><h3 id="can-i-write-custom-harnesses" tabindex="-1">Can I write custom harnesses? <a class="header-anchor" href="#can-i-write-custom-harnesses" aria-label="Permalink to &quot;Can I write custom harnesses?&quot;">​</a></h3><p>Yes. The Claude Agent SDK enables exactly this. Import the SDK in Python or TypeScript, configure desired tools, define system prompts, manage permissions, and build tailored harnesses for specific use cases. Enterprises adopt this pattern for legal review pipelines, code audits, and report generation.</p><h2 id="conclusions" tabindex="-1">Conclusions <a class="header-anchor" href="#conclusions" aria-label="Permalink to &quot;Conclusions&quot;">​</a></h2><p>The harness represents the actual product design. The model functions as interchangeable infrastructure, while the harness determines agent safety, ergonomics, real-world costs, and productivity. Claude Code versus Codex versus Cursor comparisons fundamentally compare different harnesses, not models.</p><p>For maximum Claude Code value, configure settings.json and CLAUDE.md deliberately, write modular skills over monolithic prompts, and invest in hooks automating safety checks. Anthropic&#39;s product roadmap confirms this direction: reducing prompt engineering emphasis while increasing harness engineering focus.</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><h3 id="核心命題-harness-才是真正的產品" tabindex="-1">核心命題：Harness 才是真正的產品 <a class="header-anchor" href="#核心命題-harness-才是真正的產品" aria-label="Permalink to &quot;核心命題：Harness 才是真正的產品&quot;">​</a></h3><p>claude-opus-4-7 模型本身只是 token 生成器。讓 Claude Code 能讀取檔案、執行 shell 命令、開 PR、維持 session 偏好的，是圍繞模型的軟體層——<strong>harness</strong>。</p><p>Claude Code 的智慧來自這個簡單的迭代循環：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gather history → call model → execute tools → append result → loop</span></span></code></pre></div><p>模型感知不到循環本身，只看到累積的對話歷史。Anthropic 刻意避免複雜的規劃系統，仰賴簡單工具呼叫循環。</p><h3 id="八大獨立組件" tabindex="-1">八大獨立組件 <a class="header-anchor" href="#八大獨立組件" aria-label="Permalink to &quot;八大獨立組件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>組件</th><th>職責</th><th>關鍵細節</th></tr></thead><tbody><tr><td><strong>1. Tool Executor</strong></td><td>將結構化工具請求轉為實際動作</td><td>5 類原生工具：檔案操作、搜尋、執行、網路、程式智能</td></tr><tr><td><strong>2. Permission Manager</strong></td><td>工具執行前驗證權限</td><td>4 模式：預設/自動接受編輯/Plan Mode/Auto（背景安全分類器）</td></tr><tr><td><strong>3. Hook System</strong></td><td>生命週期事件觸發的 shell 命令</td><td>12 個 hooks：SessionStart、UserPromptSubmit、PreToolUse、PostToolUse、Stop 等</td></tr><tr><td><strong>4. Context Manager</strong></td><td>管理 context window 使用</td><td>200K（標準）/ 1M（部分企業）；舊輸出清理、自動 compaction、Prompt Caching（5 分鐘 TTL）</td></tr><tr><td><strong>5. MCP Layer</strong></td><td>無需重新編譯即可加入第三方工具</td><td>MCP 工具名稱延遲載入，只有被呼叫時才載入完整 schema</td></tr><tr><td><strong>6. Skill System</strong></td><td>封裝領域知識的 Markdown + scripts</td><td>Session 開始時讀取 SKILL.md，完整內容僅在呼叫時載入</td></tr><tr><td><strong>7. Subagent Framework</strong></td><td>可獨立 context window 的子模型實例</td><td>並行獨立工作、隔離研究任務、領域專業化；<code>.claude/agents/</code> 配置</td></tr><tr><td><strong>8. Session Storage</strong></td><td>JSONL 格式的對話持久化</td><td><code>~/.claude/projects/</code> 下；支援 <code>--continue</code>、<code>--fork-session</code>、Escape×2 回退</td></tr></tbody></table><h3 id="permission-四種模式" tabindex="-1">Permission 四種模式 <a class="header-anchor" href="#permission-四種模式" aria-label="Permalink to &quot;Permission 四種模式&quot;">​</a></h3><ol><li><strong>預設</strong>：編輯和命令需要確認</li><li><strong>自動接受編輯</strong>：檔案修改自動核准</li><li><strong>Plan Mode</strong>：僅唯讀操作</li><li><strong>Auto</strong>：Sonnet 4.6 背景安全分類器（只評估用戶請求和工具呼叫，不評估模型散文）</li></ol><h3 id="三種執行環境" tabindex="-1">三種執行環境 <a class="header-anchor" href="#三種執行環境" aria-label="Permalink to &quot;三種執行環境&quot;">​</a></h3><ul><li><strong>本機</strong>：完整檔案系統、終端機、git 存取；最大自由也最大責任</li><li><strong>雲端</strong>：在 Anthropic 管理的 VM 上執行；適合卸載長時間任務</li><li><strong>遠端控制</strong>：本機執行但透過瀏覽器介面控制</li></ul><h3 id="settings-三層層級-優先序-本機-專案-全域" tabindex="-1">Settings 三層層級（優先序：本機 &gt; 專案 &gt; 全域） <a class="header-anchor" href="#settings-三層層級-優先序-本機-專案-全域" aria-label="Permalink to &quot;Settings 三層層級（優先序：本機 &gt; 專案 &gt; 全域）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.claude/settings.json           # 全域偏好</span></span>
<span class="line"><span>&lt;repo&gt;/.claude/settings.json      # 專案層級（可提交）</span></span>
<span class="line"><span>&lt;repo&gt;/.claude/settings.local.json # 私人覆蓋（不提交）</span></span></code></pre></div><h3 id="token-系統負擔" tabindex="-1">Token 系統負擔 <a class="header-anchor" href="#token-系統負擔" aria-label="Permalink to &quot;Token 系統負擔&quot;">​</a></h3><p>每次 session 的 harness 系統負擔：<strong>10K–50K tokens</strong>（安全規則、工具定義、基礎指令、CLAUDE.md 內容、auto-memory 上限 25KB、未執行 skill 描述、初始 git 狀態）。<code>/context</code> 指令顯示即時分解。</p><h3 id="與-codex-cursor-比較" tabindex="-1">與 Codex/Cursor 比較 <a class="header-anchor" href="#與-codex-cursor-比較" aria-label="Permalink to &quot;與 Codex/Cursor 比較&quot;">​</a></h3><ul><li><strong>Codex</strong>：harness 組件與模型 API 更緊密整合；工具呼叫原生於模型規格</li><li><strong>Cursor</strong>：優先 IDE 整合，用程式碼索引進行 context 檢索而非載入完整檔案</li><li><strong>Claude Code</strong>：強調透明度，破壞性操作有明確審批閘門</li></ul><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>8 組件詳解、settings.json 三層層級、10K-50K token 負擔量化均可直接使用</td></tr><tr><td>B. 創新性</td><td>8/10</td><td>Deferred tools 機制、diff-based memory management、4 種 Permission 模式詳解</td></tr><tr><td>C. 證據品質</td><td>8/10</td><td>Token 系統負擔 10K-50K、session JSONL 格式、prompt caching 5 分鐘 TTL 等具體數字</td></tr><tr><td>D. 技術深度</td><td>9/10</td><td>8 組件全部有程式碼/config 範例，FAQ 回答 5 個常見問題</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>Harness 架構知識跨 SDK 使用場景通用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>8.15/10</strong></td><td>8×0.3+8×0.2+8×0.2+9×0.15+8×0.15 = 2.4+1.6+1.6+1.35+1.2</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/refs/harness-design.md</code>（Runtime 架構參考區段）<br><strong>整合狀態</strong>：待實作</p>`,80)])])}const m=t(o,[["render",i]]);export{p as __pageData,m as default};
